import numpy as np

def select_next_node(current_node, truck_nodes, depot_node, unvisited_nodes, distance_matrix):
    if len(unvisited_nodes) == 0:
        return depot_node if current_node != depot_node else None

    current_positions = np.array([current_node] + list(truck_nodes))
    vectors_to_unvisited = {node: np.mean([np.linalg.norm([distance_matrix[current_positions[j], node] - distance_matrix[current_positions[j], i] for j in range(len(current_positions))]) for i in current_positions if i != node]) for node in unvisited_nodes}

    # Select node with the minimum aggregated directional vector magnitude
    next_node = min(vectors_to_unvisited, key=vectors_to_unvisited.get)

    return next_node
